# List Iscsi Initiator and CHAP Name if defined 
Get-VMHost | Get-VMHostHba | Where {$_.Type -eq "Iscsi"} | Select VMHost, 
Device, ChapType, @{N="CHAPName",E={$_.AuthenticationProperties.ChapName}}
